using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // ── AddItem ─────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("B", 3, 5m);

        Assert.AreEqual(25m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("A", 2, 10m);

        Assert.AreEqual(30m, _cart.CalculateTotal());
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddItem_NullOrWhiteSpaceSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem(sku!, 1, 5m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_Throws(int qty)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("A", qty, 5m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("A", 1, -1m));
    }

    // ── RemoveItem ──────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.AddItem("B", 1, 20m);

        _cart.RemoveItem("A");

        Assert.AreEqual(20m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperation()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _cart.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void RemoveItem_NullOrEmptySku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.RemoveItem(sku!));
    }

    // ── CalculateTotal ──────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemovingAllItems_ReturnsZero()
    {
        _cart.AddItem("A", 1, 10m);
        _cart.RemoveItem("A");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ─────────────────────────────────────────

    [TestMethod]
    [DataRow("SAVE10", 90)]
    [DataRow("SAVE20", 80)]
    [DataRow("HALF",   50)]
    public void ApplyCoupon_ValidCode_DiscountsTotal(string code, int expectedTotal)
    {
        _cart.AddItem("A", 1, 100m);
        _cart.ApplyCoupon(code);

        Assert.AreEqual((decimal)expectedTotal, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive()
    {
        _cart.AddItem("A", 1, 100m);
        _cart.ApplyCoupon("save10");

        Assert.AreEqual(90m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgument()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void ApplyCoupon_NullOrEmpty_Throws(string? code)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_ReplacedBySecondCoupon()
    {
        _cart.AddItem("A", 1, 100m);
        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(80m, _cart.CalculateTotal());
    }

    // ── Integration / edge cases ────────────────────────────

    [TestMethod]
    public void AddThenRemoveThenRecalculate_WorksCorrectly()
    {
        _cart.AddItem("A", 2, 15m);
        _cart.AddItem("B", 1, 30m);
        _cart.RemoveItem("B");
        _cart.ApplyCoupon("SAVE10");

        // 2 × 15 = 30, minus 10% = 27
        Assert.AreEqual(27m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ZeroPriceItem_IsAllowed()
    {
        _cart.AddItem("FREEBIE", 1, 0m);

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }
}

